BEGIN;

-- Dev/test password for every seeded user: password
-- BCrypt hash generated by the local Spring PasswordEncoder.
--
-- Front/back manual test accounts:
-- - Write tab: alice.author@plumora.test / password
-- - Reader library: clara.reader@plumora.test / password
-- - Beta reading: noah.beta@plumora.test / password
-- - Admin: admin@plumora.test / password
--
-- Expected UI split:
-- - Ecrire must show only the connected author's books.
-- - Bibliotheque must show only the connected user's progress, favorites and reviews.
-- - Decouvrir can show every PUBLISHED/PUBLIC book from every author.
--
-- This reset is intentionally scoped to the demo accounts below. It makes the
-- front/back navigation tests deterministic even after manual Swagger/app tests.
CREATE TEMP TABLE seed_users_to_reset(id_user UUID PRIMARY KEY) ON COMMIT DROP;
INSERT INTO seed_users_to_reset(id_user)
VALUES
    ('10000000-0000-4000-8000-000000000001'),
    ('10000000-0000-4000-8000-000000000002'),
    ('10000000-0000-4000-8000-000000000003'),
    ('10000000-0000-4000-8000-000000000004'),
    ('10000000-0000-4000-8000-000000000005'),
    ('10000000-0000-4000-8000-000000000006'),
    ('10000000-0000-4000-8000-000000000007'),
    ('10000000-0000-4000-8000-000000000008')
ON CONFLICT (id_user) DO NOTHING;

DELETE FROM ai_recommendation_results
WHERE request_id IN (
    SELECT id_ai_recommendation_request
    FROM ai_recommendation_requests
    WHERE user_id IN (SELECT id_user FROM seed_users_to_reset)
)
OR book_id IN (
    SELECT id_book
    FROM books
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM ai_recommendation_requests
WHERE user_id IN (SELECT id_user FROM seed_users_to_reset);

DELETE FROM ai_writing_suggestions
WHERE request_id IN (
    SELECT id_ai_writing_request
    FROM ai_writing_requests
    WHERE user_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM ai_writing_requests
WHERE user_id IN (SELECT id_user FROM seed_users_to_reset)
OR chapter_id IN (
    SELECT c.id_chapter
    FROM chapters c
    JOIN books b ON b.id_book = c.book_id
    WHERE b.author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM notifications
WHERE user_id IN (SELECT id_user FROM seed_users_to_reset);

DELETE FROM reports
WHERE reporter_id IN (SELECT id_user FROM seed_users_to_reset)
OR book_id IN (
    SELECT id_book
    FROM books
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM reviews
WHERE user_id IN (SELECT id_user FROM seed_users_to_reset)
OR book_id IN (
    SELECT id_book
    FROM books
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM favorites
WHERE user_id IN (SELECT id_user FROM seed_users_to_reset)
OR book_id IN (
    SELECT id_book
    FROM books
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM reading_progress
WHERE user_id IN (SELECT id_user FROM seed_users_to_reset)
OR book_id IN (
    SELECT id_book
    FROM books
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM beta_comments
WHERE beta_reader_id IN (SELECT id_user FROM seed_users_to_reset)
OR campaign_id IN (
    SELECT id_beta_reading_campaign
    FROM beta_reading_campaigns
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
)
OR chapter_id IN (
    SELECT c.id_chapter
    FROM chapters c
    JOIN books b ON b.id_book = c.book_id
    WHERE b.author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM beta_shared_chapters
WHERE campaign_id IN (
    SELECT id_beta_reading_campaign
    FROM beta_reading_campaigns
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
)
OR chapter_id IN (
    SELECT c.id_chapter
    FROM chapters c
    JOIN books b ON b.id_book = c.book_id
    WHERE b.author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM beta_invitations
WHERE beta_reader_id IN (SELECT id_user FROM seed_users_to_reset)
OR campaign_id IN (
    SELECT id_beta_reading_campaign
    FROM beta_reading_campaigns
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM beta_reading_campaigns
WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
OR book_id IN (
    SELECT id_book
    FROM books
    WHERE author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM chapter_versions
WHERE created_by_user_id IN (SELECT id_user FROM seed_users_to_reset)
OR chapter_id IN (
    SELECT c.id_chapter
    FROM chapters c
    JOIN books b ON b.id_book = c.book_id
    WHERE b.author_id IN (SELECT id_user FROM seed_users_to_reset)
);

DELETE FROM books
WHERE author_id IN (SELECT id_user FROM seed_users_to_reset);

DELETE FROM user_roles
WHERE id_user IN (SELECT id_user FROM seed_users_to_reset);

