INSERT INTO users (id_user, firstname, lastname, username, email, password_hash, avatar_url, bio, is_active, created_at, updated_at)
SELECT
    id_user,
    firstname,
    lastname,
    username,
    email,
    '$2a$10$hitz6ikg/grYTEyhlMlzXe2tPujxA2vHpFKU8v14gcpEWVPZrtlkm',
    'https://placehold.co/256x256?text=' || upper(left(firstname, 1)) || upper(left(lastname, 1)),
    bio,
    TRUE,
    now() - interval '20 days',
    now()
FROM seed_users
ON CONFLICT (email) DO UPDATE SET
    firstname = EXCLUDED.firstname,
    lastname = EXCLUDED.lastname,
    username = EXCLUDED.username,
    password_hash = EXCLUDED.password_hash,
    avatar_url = EXCLUDED.avatar_url,
    bio = EXCLUDED.bio,
    is_active = TRUE,
    updated_at = now();

