INSERT INTO chapters (id_chapter, book_id, title, content, chapter_order, word_count, created_at, updated_at)
VALUES
    ('30000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'La carte mouillee', 'La pluie avait efface les routes, mais pas les promesses. Maelle posa la main sur la carte et la brume repondit.', 1, 23, now() - interval '39 days', now() - interval '12 days'),
    ('30000000-0000-4000-8000-000000000002', '20000000-0000-4000-8000-000000000001', 'La ville sous le verre', 'Sous la colline, les lampes flottaient comme des lunes minuscules. Aucun habitant ne semblait vieillir.', 2, 18, now() - interval '38 days', now() - interval '12 days'),
    ('30000000-0000-4000-8000-000000000003', '20000000-0000-4000-8000-000000000001', 'Le serment des passeurs', 'Les passeurs exigeaient une histoire vraie pour ouvrir le chemin. Maelle choisit celle qui lui coutait le plus.', 3, 20, now() - interval '37 days', now() - interval '11 days'),
    ('30000000-0000-4000-8000-000000000004', '20000000-0000-4000-8000-000000000002', 'Rideau noir', 'Le theatre sentait la poussiere chaude et les roses fanees. Au centre, un violon jouait sans musicien.', 1, 18, now() - interval '29 days', now() - interval '5 days'),
    ('30000000-0000-4000-8000-000000000005', '20000000-0000-4000-8000-000000000002', 'La note qui revient', 'Chaque spectateur entendait une melodie differente, mais tous pleuraient au meme moment.', 2, 15, now() - interval '28 days', now() - interval '5 days'),
    ('30000000-0000-4000-8000-000000000006', '20000000-0000-4000-8000-000000000003', 'Quai 17', 'A minuit dix-sept, le train entra sans bruit. Les panneaux annoncerent une destination impossible.', 1, 15, now() - interval '17 days', now() - interval '2 days'),
    ('30000000-0000-4000-8000-000000000007', '20000000-0000-4000-8000-000000000003', 'Le controleur', 'Le controleur connaissait le nom des morts et poinconnait les billets avec une aiguille d''argent.', 2, 16, now() - interval '16 days', now() - interval '2 days'),
    ('30000000-0000-4000-8000-000000000008', '20000000-0000-4000-8000-000000000004', 'Brouillon vivant', 'Le jardin changeait les phrases avant meme qu''Alice ne les pense.', 1, 11, now() - interval '9 days', now()),
    ('30000000-0000-4000-8000-000000000009', '20000000-0000-4000-8000-000000000005', 'Zone blanche', 'Les radios se turent ensemble. A partir de la borne rouge, chaque parole demandait un prix.', 1, 16, now() - interval '7 days', now()),
    ('30000000-0000-4000-8000-000000000010', '20000000-0000-4000-8000-000000000005', 'La caravane muette', 'Personne ne parlait dans la caravane, mais les carnets se remplissaient de phrases inconnues.', 2, 15, now() - interval '6 days', now())
ON CONFLICT (id_chapter) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    chapter_order = EXCLUDED.chapter_order,
    word_count = EXCLUDED.word_count,
    updated_at = EXCLUDED.updated_at;

