INSERT INTO chapters (id_chapter, book_id, title, content, chapter_order, word_count, created_at, updated_at)
VALUES
    ('30000000-0000-4000-8000-000000000011', '20000000-0000-4000-8000-000000000006', 'Les pages lumineuses', 'La reliure vibra sous les doigts d Iris. Chaque luciole semblait porter le nom d une ville disparue.', 1, 18, now() - interval '13 days', now() - interval '2 hours'),
    ('30000000-0000-4000-8000-000000000012', '20000000-0000-4000-8000-000000000006', 'Le marche des cartes', 'Au marche du matin, personne ne vendait de fruits. On y echangeait des routes et des souvenirs.', 2, 17, now() - interval '12 days', now() - interval '2 hours'),
    ('30000000-0000-4000-8000-000000000013', '20000000-0000-4000-8000-000000000007', 'Phare allume', 'Le phare gardait la cote comme une veilleuse geante. Lina entendit une voix dans l ecume.', 1, 17, now() - interval '24 days', now() - interval '1 day'),
    ('30000000-0000-4000-8000-000000000014', '20000000-0000-4000-8000-000000000007', 'Le carnet sale', 'Les pages du carnet etaient collees par le sel, mais une carte respirait encore entre deux lignes.', 2, 17, now() - interval '23 days', now() - interval '1 day'),
    ('30000000-0000-4000-8000-000000000015', '20000000-0000-4000-8000-000000000007', 'La nuit sans maree', 'Cette nuit-la, l ocean resta immobile. Les bateaux semblaient suspendus a une pensee.', 3, 15, now() - interval '22 days', now() - interval '1 day'),
    ('30000000-0000-4000-8000-000000000016', '20000000-0000-4000-8000-000000000008', 'Verre brise', 'Le dossier etait clos, mais les fragments continuaient de reflechir des scenes inachevees.', 1, 13, now() - interval '59 days', now() - interval '20 days'),
    ('30000000-0000-4000-8000-000000000017', '20000000-0000-4000-8000-000000000009', 'Terminus inconnu', 'Le tram depassa le dernier arret officiel et les neons de Lumen apparurent dans le brouillard.', 1, 17, now() - interval '27 days', now() - interval '3 days'),
    ('30000000-0000-4000-8000-000000000018', '20000000-0000-4000-8000-000000000009', 'Le passager sans ombre', 'Un homme sans ombre laissa tomber un badge de presse date du lendemain.', 2, 13, now() - interval '26 days', now() - interval '3 days'),
    ('30000000-0000-4000-8000-000000000019', '20000000-0000-4000-8000-000000000010', 'La cle du toit', 'Nora trouva la cle dans la boite aux lettres de son voisin, accompagnee d une invitation au coucher du soleil.', 1, 20, now() - interval '31 days', now() - interval '7 days'),
    ('30000000-0000-4000-8000-000000000020', '20000000-0000-4000-8000-000000000010', 'Terrasse vingt-deux', 'La terrasse etait couverte de basilic, de coussins rouges et de secrets mal gardes.', 2, 14, now() - interval '30 days', now() - interval '7 days'),
    ('30000000-0000-4000-8000-000000000021', '20000000-0000-4000-8000-000000000011', 'Inventaire du ciel', 'Chaque etoile tombee recevait une etiquette, une couverture et une promesse de retour.', 1, 15, now() - interval '35 days', now() - interval '4 days'),
    ('30000000-0000-4000-8000-000000000022', '20000000-0000-4000-8000-000000000011', 'La constellation pliee', 'La constellation tenait dans une enveloppe. Quand Maya l ouvrit, la piece devint plus vaste.', 2, 15, now() - interval '34 days', now() - interval '4 days'),
    ('30000000-0000-4000-8000-000000000023', '20000000-0000-4000-8000-000000000012', 'Note de depart', 'Brouillon prive reserve a Maya pour verifier les filtres auteur.', 1, 10, now() - interval '8 days', now() - interval '1 hour')
